/**
 * Get frameworks available for a given niche.
 * Returns all universal frameworks + frameworks matching the niche.
 */
export function getFrameworksForNiche(niche) {
  if (!niche) return BUILDER_FRAMEWORKS.filter(f => f.niches === null);
  return BUILDER_FRAMEWORKS.filter(
    f => f.niches === null || (Array.isArray(f.niches) && f.niches.includes(niche))
  );
}

/**
 * Get a single framework by ID.
 */
export function getFrameworkById(id) {
  return BUILDER_FRAMEWORKS.find(f => f.id === id) || null;
}
